"use client";

import { useEffect, useState, useRef } from "react";
import { motion, useSpring } from "framer-motion";

export default function AdminCursor() {
    const [letterIndex, setLetterIndex] = useState(0);
    const springX = useSpring(-100, { stiffness: 500, damping: 28 }); // Start off-screen
    const springY = useSpring(-100, { stiffness: 500, damping: 28 });

    // Use refs for high-frequency coordinate math without triggering unnecessary React renders
    const lastPos = useRef({ x: 0, y: 0 });
    const accumulatedDistance = useRef(0);

    const THRESHOLD = 100; // Pixels distance threshold to cycle the letter
    const letters = ["N", "O", "V", "E", "N", "O"];
    const currentLetter = letters[letterIndex];

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            const { clientX, clientY } = e;
            springX.set(clientX);
            springY.set(clientY);

            // Calculate Euclidean distance since last poll
            if (lastPos.current.x !== 0 || lastPos.current.y !== 0) {
                const dx = clientX - lastPos.current.x;
                const dy = clientY - lastPos.current.y;
                const distance = Math.hypot(dx, dy);

                accumulatedDistance.current += distance;

                if (accumulatedDistance.current >= THRESHOLD) {
                    setLetterIndex((prev) => (prev + 1) % letters.length);
                    // Subtract threshold to carry over modulo distance smoothly, or reset to 0
                    accumulatedDistance.current = 0;
                }
            }

            lastPos.current = { x: clientX, y: clientY };
        };

        window.addEventListener("mousemove", handleMouseMove);
        return () => window.removeEventListener("mousemove", handleMouseMove);
    }, [springX, springY]);

    return (
        <motion.div
            className="fixed top-0 left-0 w-12 h-12 rounded-full border border-terracotta bg-terracotta/5 backdrop-blur-sm pointer-events-none z-[9999] flex items-center justify-center text-terracotta font-lovelo text-xl shadow-sm"
            style={{
                x: springX,
                y: springY,
                translateX: "-50%",
                translateY: "-50%",
            }}
        >
            <motion.span
                key={currentLetter}
                initial={{ opacity: 0, scale: 0.5, rotate: -45 }}
                animate={{ opacity: 1, scale: 1, rotate: 0 }}
                transition={{ duration: 0.4, type: "spring" }}
            >
                {currentLetter}
            </motion.span>
        </motion.div>
    );
}

"use client";

import { Sector } from "@/hooks/useAgencyData";
import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import { useEffect, useState } from "react";
import UniversalFooter from "./UniversalFooter";
import ClientCarousel from "./ClientCarousel";
import PortfolioCarousel from "./PortfolioCarousel";

// Horizontal Slide Component (Now every slide scroll vertically)
function HorizontalSlide({
    sector,
    isActive,
    isBefore,
    isAfter,
}: {
    sector: Sector;
    isActive: boolean;
    isBefore: boolean;
    isAfter: boolean;
}) {
    const isInicio = sector.id === "inicio";

    // Parallax Background Setup (Opposite to Mouse X/Y)
    const mouseX = useMotionValue(0);
    const mouseY = useMotionValue(0);
    const smoothX = useSpring(mouseX, { stiffness: 100, damping: 30 });
    const smoothY = useSpring(mouseY, { stiffness: 100, damping: 30 });
    const moveX = useTransform(smoothX, [0, typeof window !== "undefined" ? window.innerWidth : 1000], [-15, 15]);
    const moveY = useTransform(smoothY, [0, typeof window !== "undefined" ? window.innerHeight : 1000], [-15, 15]);

    useEffect(() => {
        if (!isActive) return;
        const handleMouseMove = (e: MouseEvent) => {
            mouseX.set(e.clientX);
            mouseY.set(e.clientY);
        };
        window.addEventListener("mousemove", handleMouseMove);
        return () => window.removeEventListener("mousemove", handleMouseMove);
    }, [isActive, mouseX, mouseY]);

    return (
        <motion.div
            initial={false}
            animate={{
                x: isBefore ? "-100%" : isAfter ? "100%" : "0%",
                opacity: isActive ? 1 : 0.4,
                scale: isActive ? 1 : 0.9,
            }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className={`absolute top-0 left-0 w-[100vw] h-[100vh] will-change-transform flex overflow-hidden ${isActive ? "overflow-y-auto" : "overflow-y-hidden"
                }`}
        >
            {/* Background Parallax Layer */}
            <motion.div
                style={{ x: moveX, y: moveY }}
                className="fixed top-[-5%] left-[-5%] w-[110%] h-[110%] -z-10 object-cover pointer-events-none"
            >
                {sector.mediaType === "video" ? (
                    <video
                        src={sector.mediaUrl}
                        autoPlay
                        loop
                        muted
                        playsInline
                        className="w-full h-full object-cover"
                    />
                ) : (
                    <img src={sector.mediaUrl} alt={sector.title} className="w-full h-full object-cover" />
                )}
            </motion.div>

            {/* Main Content Render */}
            <div className="relative w-full min-h-full">
                {isInicio ? (
                    <InicioVerticalFlow sector={sector} />
                ) : (
                    <SectorVerticalFlow sector={sector} />
                )}
            </div>
        </motion.div>
    );
}

// Sub-Component: Vertical Sections for Index 0 (Inicio)
function InicioVerticalFlow({ sector }: { sector: Sector }) {
    return (
        <div className="w-full flex flex-col items-center">
            {/* 1. Hero */}
            <section className="w-full h-screen flex flex-col justify-end p-12 lg:p-24 relative snap-start">
                {/* Heavy Top Gradient & Lower Scrim for text legibility */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-black/20 pointer-events-none -z-1" />

                <h2 className="relative z-10 text-white/45 mix-blend-difference font-lovelo text-6xl md:text-8xl lg:text-9xl tracking-widest uppercase mb-4 leading-none max-w-5xl">
