                        <span className="font-Montserrat font-semibold uppercase tracking-widest text-[10px] md:text-xs text-sand">{client.brandName}</span>
                    </div>
                ))}
            </motion.div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { motion, useSpring } from "framer-motion";

export default function CustomCursor({ activeIndex }: { activeIndex: number }) {
    const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
    const springX = useSpring(0, { stiffness: 500, damping: 28 });
    const springY = useSpring(0, { stiffness: 500, damping: 28 });

    // Map indexes to the static N-O-V-E-N-O letters
    const staticLetters = ["N", "O", "V", "E", "N", "O"];
    const currentLetter = staticLetters[activeIndex] || "N";

    useEffect(() => {
        const updateMousePosition = (e: MouseEvent) => {
            setMousePosition({ x: e.clientX, y: e.clientY });
            springX.set(e.clientX);
            springY.set(e.clientY);
        };

        window.addEventListener("mousemove", updateMousePosition);
        return () => window.removeEventListener("mousemove", updateMousePosition);
    }, [springX, springY]);

    return (
        <motion.div
            className="fixed top-0 left-0 w-12 h-12 rounded-full border border-sand bg-foreground/10 backdrop-blur-md mix-blend-difference pointer-events-none z-[9999] flex items-center justify-center text-sand font-lovelo text-xl pointer-events-none"
            style={{
                x: springX,
                y: springY,
                translateX: "-50%",
                translateY: "-50%",
            }}
        >
            <motion.span
                key={currentLetter}
                initial={{ opacity: 0, scale: 0.5, rotate: -45 }}
                animate={{ opacity: 1, scale: 1, rotate: 0 }}
                transition={{ duration: 0.4, type: "spring" }}
            >
                {currentLetter}
            </motion.span>
        </motion.div>
    );
}

"use client";

import { PortfolioItem } from "@/hooks/useAgencyData";
import { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";

export default function PortfolioCarousel({ items }: { items?: PortfolioItem[] }) {
    const targetRef = useRef<HTMLDivElement>(null);

    // Create a scroll-linked transformation for true horizontal parallax mapping
    const { scrollYProgress } = useScroll({
        target: targetRef,
        offset: ["start end", "end start"],
    });

    // Moves the inner container horizontally strictly dependent on the pure vertical scroll progression
    const x = useTransform(scrollYProgress, [0, 1], ["20%", "-40%"]);

    if (!items || items.length === 0) return null;

    return (
        <section
            ref={targetRef}
            className="relative w-full h-[150vh] bg-black"
        // The section is 150vh tall just to give the user enough scroll space to see the horizontal translation hook.
        >
            <div className="sticky top-0 w-full h-screen overflow-hidden flex flex-col justify-center">
                <div className="px-12 lg:px-24 mb-12">
                    <h3 className="text-teal font-lovelo text-4xl uppercase tracking-widest">Portafolio</h3>
                    <p className="text-sand/60 font-Montserrat mt-2 text-sm uppercase tracking-widest">Explora nuestros trabajos recientes.</p>
                </div>

                <motion.div style={{ x }} className="flex gap-8 px-12 lg:px-24 min-w-max">
                    {items.map((item) => (
                        <div key={item.id} className="relative w-[70vw] md:w-[50vw] lg:w-[40vw] aspect-[16/9] group overflow-hidden">
                            {item.mediaType === "video" ? (
                                <video src={item.mediaUrl} autoPlay loop muted playsInline className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105" />
                            ) : (
                                <img src={item.mediaUrl} alt={item.title || "Portfolio"} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105" />
                            )}
                            <div className="absolute inset-0 bg-black/40 group-hover:bg-transparent transition-colors duration-500" />

                            {item.title && (
                                <div className="absolute bottom-6 left-6 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                                    <h4 className="text-white font-lovelo text-2xl drop-shadow-lg">{item.title}</h4>
                                </div>
                            )}
                        </div>
                    ))}
                </motion.div>
            </div>
        </section>
    );
}

