        mediaUrl: "https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&q=80&w=2000",
        mediaType: "image",
        clients: [],
        portfolio: [
            { id: "e_p1", mediaUrl: "https://images.unsplash.com/photo-1492684223066-81342ee5ff30?auto=format&fit=crop&q=80&w=800", mediaType: "image" },
            { id: "e_p2", mediaUrl: "https://images.unsplash.com/photo-1478147427282-58a87a120781?auto=format&fit=crop&q=80&w=800", mediaType: "image" },
        ]
    },
];

export function useAgencyData() {
    const [sectors, setSectors] = useState<Sector[]>(defaultData);
    const [footerConfig, setFooterConfig] = useState<FooterConfig>(defaultFooter);
    const [quoteServices, setQuoteServices] = useState<QuoteService[]>(defaultServices);
    const [leads, setLeads] = useState<Lead[]>(defaultLeads);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchRealData = async () => {
            try {
                // 1. OBTENER SECTORES
                const { data: sectorsData, error: sectorsError } = await supabase
                    .from("sectors")
                    .select("*");

                if (sectorsError) throw sectorsError;

                if (sectorsData && sectorsData.length > 0) {
                    // Mapear campos JSONB a la estructura local
                    const mappedSectors: Sector[] = sectorsData.map((s: any) => ({
                        id: s.id as SectorType,
                        title: s.title,
                        description: s.description,
                        mediaUrl: s.media_url,
                        mediaType: s.media_type,
                        teamMembers: s.team_members || [],
                        collaborators: s.collaborators || [],
                        clients: s.clients || [],
                        portfolio: s.portfolio || [],
                        aboutText: defaultData.find(d => d.id === s.id)?.aboutText // fallback temporal
                    }));
                    setSectors(mappedSectors);
                } else {
                    setSectors(defaultData); // Fallback a mock data si la DB está vacía
                }

                // 2. OBTENER FOOTER
                const { data: footerData, error: footerError } = await supabase
                    .from("footer_config")
                    .select("*")
                    .eq("id", 1)
                    .single();

                if (!footerError && footerData) {
                    setFooterConfig({
                        email: footerData.email || "",
                        phone: footerData.phone || "",
                        address: footerData.address || "",
                        social: {
                            instagram: footerData.instagram || "",
                            linkedin: footerData.linkedin || ""
                        }
                    });
                }

                // 3. OBTENER SERVICIOS
                const { data: servicesData, error: servicesError } = await supabase
                    .from("quote_services")
                    .select("*")
                    .order("created_at", { ascending: true });

                if (!servicesError && servicesData && servicesData.length > 0) {
                    setQuoteServices(servicesData.map(s => ({ id: s.id, name: s.name })));
                } else {
                    setQuoteServices(defaultServices);
                }

                // 4. OBTENER LEADS (CRM)
                const { data: leadsData, error: leadsError } = await supabase
                    .from("leads")
                    .select("*")
                    .order("created_at", { ascending: false });

                if (!leadsError && leadsData && leadsData.length > 0) {
                    setLeads(leadsData.map(l => ({
                        id: l.id,
                        fullName: l.full_name,
                        email: l.email,
                        phone: l.phone,
                        message: l.message,
                        services: l.services || [],
                        status: l.status as LeadStatus,
                        createdAt: l.created_at
                    })));
                } else {
                    setLeads(defaultLeads);
                }

            } catch (e) {
                console.error("Failed to fetch data from Supabase", e);
                // Fallback a localStorage si Supabase falla o no está configurado aún
                const savedSectors = localStorage.getItem("noveno_sectors_v3");
                if (savedSectors) setSectors(JSON.parse(savedSectors));
            } finally {
                setIsLoading(false);
            }
        };

        fetchRealData();
    }, []);

    const updateSectorContent = async (id: string, mediaUrl: string, mediaType: "image" | "video") => {
        try {
            await supabase.from("sectors").update({ media_url: mediaUrl, media_type: mediaType }).eq("id", id);
            const newSectors = sectors.map((s) => (s.id === id ? { ...s, mediaUrl, mediaType } : s));
            setSectors(newSectors);
            localStorage.setItem("noveno_sectors_v3", JSON.stringify(newSectors)); // Cache backup
        } catch (e) { console.error(e); }
    };

    const updateTeamMembers = async (sectorId: string, members: TeamMember[]) => {
        try {
            await supabase.from("sectors").update({ team_members: members }).eq("id", sectorId);
            const newSectors = sectors.map((s) => (s.id === sectorId ? { ...s, teamMembers: members } : s));
            setSectors(newSectors);
        } catch (e) { console.error(e); }
    };

    const updateCollaborators = async (sectorId: string, collabs: TeamMember[]) => {
        try {
            await supabase.from("sectors").update({ collaborators: collabs }).eq("id", sectorId);
            const newSectors = sectors.map((s) => (s.id === sectorId ? { ...s, collaborators: collabs } : s));
            setSectors(newSectors);
        } catch (e) { console.error(e); }
    };

    const updateClients = async (sectorId: string, clients: ClientLogo[]) => {
        try {
            await supabase.from("sectors").update({ clients }).eq("id", sectorId);
            const newSectors = sectors.map((s) => (s.id === sectorId ? { ...s, clients } : s));
            setSectors(newSectors);
        } catch (e) { console.error(e); }
    };

    const updatePortfolio = async (sectorId: string, portfolio: PortfolioItem[]) => {
        try {
            await supabase.from("sectors").update({ portfolio }).eq("id", sectorId);
            const newSectors = sectors.map((s) => (s.id === sectorId ? { ...s, portfolio } : s));
            setSectors(newSectors);
        } catch (e) { console.error(e); }
    };

    const updateFooter = async (newFooter: FooterConfig) => {
        try {
            await supabase.from("footer_config").upsert({
                id: 1,
                email: newFooter.email,
                phone: newFooter.phone,
                address: newFooter.address,
                instagram: newFooter.social.instagram,
                linkedin: newFooter.social.linkedin
            });
            setFooterConfig(newFooter);
        } catch (e) { console.error(e); }
    }

    const updateQuoteServices = async (services: QuoteService[]) => {
        try {
            // Un upsert masivo o borrar/insertar
            // Por simplicidad en este update: borramos toodos e insertamos los nuevos
            await supabase.from("quote_services").delete().neq("id", "0"); // wipe all

            const toInsert = services.map(s => {
                // Si es un id temporal generado con Date.now(), quitamos el ID para que supabase asigne un UUID
                if (s.id.length < 20) return { name: s.name };
                return { id: s.id, name: s.name };
            });

            if (toInsert.length > 0) {
                const { data } = await supabase.from("quote_services").insert(toInsert).select();
                if (data) {
                    setQuoteServices(data.map(d => ({ id: d.id, name: d.name })));
                    return;
                }
            } else {
                setQuoteServices([]);
            }
        } catch (e) { console.error(e); }

        // Optimistic UI/Fallback
        setQuoteServices(services);
    };

    const addLead = async (leadData: Omit<Lead, "id" | "createdAt" | "status">) => {
        try {
            const { data, error } = await supabase.from("leads").insert({
                full_name: leadData.fullName,
                email: leadData.email,
                phone: leadData.phone,
                message: leadData.message,
                services: leadData.services,
                status: "nuevo"
            }).select().single();

            if (error) throw error;

            if (data) {
                const newLead: Lead = {
                    id: data.id,
                    fullName: data.full_name,
                    email: data.email,
                    phone: data.phone,
                    message: data.message,
                    services: data.services || [],
                    status: data.status as LeadStatus,
                    createdAt: data.created_at
                };
                setLeads([newLead, ...leads]);
            }
        } catch (e) {
            console.error("Error al enviar el formulario", e);
            // Fallback optimista si falla (para demo)
            const fallbackLead: Lead = {
                ...leadData,
                id: Date.now().toString(),
                status: "nuevo",
                createdAt: new Date().toISOString()
            };
            setLeads([fallbackLead, ...leads]);
        }
    };

    const updateLeadStatus = async (leadId: string, newStatus: LeadStatus) => {
        // Optimistic Update UI primero para que se sienta inmediato en el Drag & Drop
        const prevLeads = [...leads];
        setLeads(leads.map(l => l.id === leadId ? { ...l, status: newStatus } : l));

        try {
            const { error } = await supabase.from("leads").update({ status: newStatus }).eq("id", leadId);
            if (error) throw error;
        } catch (e) {
            console.error(e);
            setLeads(prevLeads); // Revertir si falla en Supabase
        }
    };

    return {
        sectors,
        footerConfig,
        quoteServices,
        leads,
        isLoading,
        updateSectorContent,
        updateTeamMembers,
        updateCollaborators,
        updateClients,
        updatePortfolio,
        updateFooter,
        updateQuoteServices,
        addLead,
        updateLeadStatus
    };
}
